import React, { useEffect, useState } from 'react';

const API_AUTH_URL = 'https://api.yourwebsite.com/oauth/auth';
const API_TOKEN_URL = 'https://api.yourwebsite.com/oauth/token';
const REDIRECT_URI = 'https://yourwebsite.com/callback';
const CLIENT_ID = 'your_client_id';
const CLIENT_SECRET = 'your_client_secret';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [token, setToken] = useState('');

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');

    if (code) {
      fetchAccessToken(code);
    } else {
      const localToken = localStorage.getItem('token');

      if (localToken) {
        setToken(localToken);
        setIsAuthenticated(true);
      }
    }
  }, []);

  const fetchAccessToken = (code) => {
    fetch(API_TOKEN_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: `grant_type=authorization_code&code=${code}&client_id=${CLIENT_ID}&client_secret=${CLIENT_SECRET}&redirect_uri=${REDIRECT_URI}`,
    })
      .then((response) => response.json())
      .then((data) => {
        localStorage.setItem('token', data.access_token);
        setToken(data.access_token);
        setIsAuthenticated(true);
      });
  };

  const handleLogin = () => {
    window.location.href = `${API_AUTH_URL}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}`;
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    setToken('');
    setIsAuthenticated(false);
  };

  if (isAuthenticated) {
    return (
      <div>
        <h1>Welcome!</h1>
        <button onClick={handleLogout}>Logout</button>
      </div>
    );
  } else {
    return (
      <div>
        <h1>Please log in</h1>
        <button onClick={handleLogin}>Login</button>
      </div>
    );
  }
};

export default App;